/**
 * Discriminated union of every webhook event the Bird platform emits.
 *
 * Each variant is the full delivery body: `type` names the event, `timestamp` is when the
 * event occurred, and `data` carries the event-specific payload. The `type` property
 * selects the variant, and the generated SDK types narrow on it, so your code can switch
 * on the event id and read the variant-specific payload fields without casting.
 *
 * Delivery metadata (the event id and per-attempt signature headers) rides in HTTP headers
 * per Standard Webhooks and is handled by the SDK's webhook verification helper, which
 * returns one of these variants. See the [webhooks guide](/docs/guides/webhooks) for
 * header names and the verification recipe.
 *
 */
export type WebhookEventWritable =
  | ({
      type: "domain.failed";
    } & EventDomainFailed)
  | ({
      type: "domain.verified";
    } & EventDomainVerified)
  | ({
      type: "email.accepted";
    } & EventEmailAccepted)
  | ({
      type: "email.bounced";
    } & EventEmailBounced)
  | ({
      type: "email.canceled";
    } & EventEmailCanceled)
  | ({
      type: "email.clicked";
    } & EventEmailClicked)
  | ({
      type: "email.complained";
    } & EventEmailComplained)
  | ({
      type: "email.deferred";
    } & EventEmailDeferred)
  | ({
      type: "email.delivered";
    } & EventEmailDelivered)
  | ({
      type: "email.list_unsubscribed";
    } & EventEmailListUnsubscribed)
  | ({
      type: "email.opened";
    } & EventEmailOpened)
  | ({
      type: "email.out_of_band_bounce";
    } & EventEmailOutOfBandBounce)
  | ({
      type: "email.processed";
    } & EventEmailProcessed)
  | ({
      type: "email.received";
    } & EventEmailReceived)
  | ({
      type: "email.rejected";
    } & EventEmailRejected)
  | ({
      type: "email.scheduled";
    } & EventEmailScheduled)
  | ({
      type: "email.unsubscribed";
    } & EventEmailUnsubscribed)
  | ({
      type: "email_mailbox.message_delivered";
    } & EventEmailMailboxMessageDelivered)
  | ({
      type: "email_mailbox.message_failed";
    } & EventEmailMailboxMessageFailed)
  | ({
      type: "email_mailbox.message_received";
    } & EventEmailMailboxMessageReceived)
  | ({
      type: "email_mailbox.message_sent";
    } & EventEmailMailboxMessageSent)
  | ({
      type: "email_mailbox.suspended";
    } & EventEmailMailboxSuspended)
  | ({
      type: "email_mailbox.thread_created";
    } & EventEmailMailboxThreadCreated)
  | ({
      type: "email_suppression.created";
    } & EventEmailSuppressionCreated)
  | ({
      type: "sms.accepted";
    } & EventSmsAccepted)
  | ({
      type: "sms.delivered";
    } & EventSmsDelivered)
  | ({
      type: "sms.expired";
    } & EventSmsExpired)
  | ({
      type: "sms.failed";
    } & EventSmsFailedWritable)
  | ({
      type: "sms.rejected";
    } & EventSmsRejectedWritable)
  | ({
      type: "sms.sent";
    } & EventSmsSent)
  | ({
      type: "sms.tfn_verification.approved";
    } & EventSmsTfnVerificationApproved)
  | ({
      type: "sms.tfn_verification.info_requested";
    } & EventSmsTfnVerificationInfoRequested)
  | ({
      type: "sms.tfn_verification.rejected";
    } & EventSmsTfnVerificationRejected)
  | ({
      type: "sms.tfn_verification.submitted";
    } & EventSmsTfnVerificationSubmitted)
  | ({
      type: "sms.undelivered";
    } & EventSmsUndeliveredWritable)
  | ({
      type: "voice.call.answered";
    } & EventVoiceCallAnswered)
  | ({
      type: "voice.call.ended";
    } & EventVoiceCallEnded)
  | ({
      type: "voice.call.initiated";
    } & EventVoiceCallInitiated)
  | ({
      type: "whatsapp.accepted";
    } & EventWhatsAppAccepted)
  | ({
      type: "whatsapp.delivered";
    } & EventWhatsAppDelivered)
  | ({
      type: "whatsapp.failed";
    } & EventWhatsAppFailedWritable)
  | ({
      type: "whatsapp.read";
    } & EventWhatsAppRead)
  | ({
      type: "whatsapp.sent";
    } & EventWhatsAppSent);

